import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import org.owasp.encoder.Encode;

public class InputHandler {

    public void handleUserInput(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");

        // Encode user input using OWASP Java Encoder
        String encodedUserInput = Encode.forHtml(userInput);

        // Properly handle user input with encoding to prevent XSS
        String output = "<p>User input: " + encodedUserInput + "</p>";

        response.getWriter().write(output);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
